use std::collections::HashSet; impl Solution { pub fn min_cost(black_g: Vec<Vec<i32>>) -> i32 { let (black_m, black_n) = (black_g.len(), black_g[0].len()); let mut black_dp = vec![vec![HashSet::new(); black_n]; black_m]; black_dp[0][0].insert(black_g[0][0]); for r in 0..black_m { for c in 0..black_n { let black_cur = black_dp[r][c].clone(); for black_v in black_cur { if r + 1 < black_m { black_dp[r + 1][c].insert(black_v ^ black_g[r + 1][c]); } if c + 1 < black_n { black_dp[r][c + 1].insert(black_v ^ black_g[r][c + 1]); } } } } *black_dp[black_m - 1][black_n - 1].iter().min().unwrap() } }